    private int reglaCount = 1; // Contador secuencial
    private java.util.List<String> listaLogs = new java.util.ArrayList<>();

    public void printLog(String regla) {
        // Formateamos con el número de paso (ej: 001. Regla: ...)
        String mensaje = String.format("%03d. Regla aplicada: %s", reglaCount++, regla);
        listaLogs.add(mensaje);
        System.out.println(mensaje);
    }

    public java.util.List<String> getLogs() {
        return listaLogs;
    }

    public void syntax_error(Symbol s){
        // Esto solo imprime un aviso temporal en consola
        System.out.println("Aviso: Error sintáctico cerca de la línea " + (s.left + 1));
    }

    public void unrecovered_syntax_error(Symbol s) throws java.lang.Exception{
        // Construimos el mensaje y LANZAMOS la excepción
        String mensaje = "Error en la linea " + (s.left + 1) + " Columna " + s.right + ". Valor simbolo '" + s.value + "' no esperado.";

        // Lanzamos la excepción directamente
        throw new SyntaxException(mensaje);
    }


